mapper.update:
update dms_registration
set
    status = #{status},
    end_attendance = #{endAttendance}
where id = #{id}

mapper.select:
select dr.id as id, p.medical_record_no as medicalNo, p.name as name, case when p.gender = 1 then '男' else '女' end as gender, COALESCE(TIMESTAMPDIFF(YEAR, p.date_of_birth, dr.attendance_date), 0) as age, dr.status as status, dr.end_attendance as endAttendance, skd.noon as noon from dms_registration dr left join pms_patient p on dr.patient_id = p.id left join sms_skd skd on dr.skd_id = skd.id where dr.attendance_date = #{attendanceDate}
and skd.noon = #{noon}
and (dr.end_attendance = #{endAttendance} or dr.end_attendance is null) and dr.status <> #{canceledStatus}
and skd.staff_id = #{staffId}
and dr.dept_id = #{deptId}
and (p.name like concat('%', #{keyword}, '%') or p.medical_record_no like concat('%', #{keyword}, '%'))
order by dr.create_time asc

mapper.update:
update dms_registration dr
join sms_skd skd on dr.skd_id = skd.id
set dr.status = #{status}
where dr.id = #{id}
  and skd.staff_id = #{staffId}
  and dr.status = #{unfinishedStatus}
  and (dr.end_attendance = #{unfinishedEndAttendance} or dr.end_attendance is null)
  and dr.status <> #{canceledStatus}

update dms_registration dr
join sms_skd skd on dr.skd_id = skd.id
set
    dr.end_attendance = #{endAttendance},
    dr.status = #{status}
where dr.id = #{id}
  and skd.staff_id = #{staffId}
  and (dr.end_attendance = #{unfinishedEndAttendance} or dr.end_attendance is null)
  and dr.status <> #{canceledStatus}
